#include<iostream>
using namespace std;
int a[51],b[51],c[51];
int dp[501][501];
int main() {
	int m,n,k;
	cin>>m>>n>>k;
	for(int i=1; i<=k; i++) cin>>a[i]>>b[i]>>c[i];
	for(int i=1; i<=k; i++) for(int j=m; j>=a[i]; j--) for(int l=n; l>=b[i]; l--) dp[j][l]=max(dp[j][l],dp[j-a[i]][l-b[i]]+c[i]);
	cout<<dp[m][n];
	return 0;
}
